def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(a, 2 * a + 1):
                    val = ((ratio - a) ** 6) / (a * b * 1.1 + 0.5)
                    freq_mod = np.sin(ratio * b / (a + 0.8)) * np.cos(ratio * (a+b)/3)
                    priority += val * freq_mod * ((-1) ** (a+b)) * (np.log1p(b) / 3)
            priority += ((np.exp(ratio - 8) * np.sin(ratio * 1.3)) ** 1.7) * np.tanh(ratio - 7)
        elif 5 < ratio <= 8:
            for p in range(2, int(np.ceil(ratio)) + 4):
                for q in range(1, p + 4):
                    term = ((ratio - p) ** 4) * np.cos(ratio * p * 0.95) / (q + 1)
                    priority += np.tanh(term) * 1.5 * np.sin(q + p)
            priority += np.log(ratio) * 12 - np.tanh(ratio - 5) * 3 + np.sqrt(ratio)
        elif 2 <= ratio <= 5:
            s1 = 0
            s2 = 0
            for r in range(1, 15):
                s1 += ((ratio - 2) ** r) / (r * 2.1) * np.cos(r * ratio * 1.3)
                s2 += ((ratio - 2) ** (r/2)) / (r + 1) * np.sin(r * ratio * 0.9)
            priority = (s1 * np.cos(9 * ratio)) - np.log(ratio) * 7 + np.tanh(5 - ratio) * 2.1 + s2 * 0.8
            for z in range(1, 5):
                priority += np.sin(z * ratio * i) * ((ratio - 1.9) ** z) / (z + 1)
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 20):
                s += ((2 - ratio) ** n) / (n ** 2 + 1)
            if bin_cap < item * 1.05:
                penalty = np.sqrt(item**1.1 / (bin_cap + 0.7)) * 4.2
            else:
                penalty = np.cos(22 * ratio) * 2.8
            exp_part = np.exp(-1.7 / (ratio + 0.04))
            priority = s + penalty + exp_part
            for m in range(1, 7):
                waves = np.sin(m * ratio * i * 1.05) * ((ratio - 0.95) ** m) / m
                priority += waves
        elif 0.4 <= ratio < 1:
            s = 0
            for n in range(1, 18):
                s += ((1 - ratio) ** n) / (n * 3.8) * np.cos(n * ratio * 1.1)
            priority = s
            if (i * int(item * 1.7)) % 5 == 1:
                priority *= np.log1p(bin_cap + 4) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.3) * 0.75 * ((-1) ** j)
        elif 0.15 <= ratio < 0.4:
            s = 0
            for k in range(1, 15):
                s += ((0.4 - ratio) ** k) / (k * 2.5) * np.cos(k * ratio * 2.3) * ((-1) ** k)
            priority = s + 1.5 / (bin_cap + 4)
            if int(item * 1.5) % 3 == 1:
                priority *= 3
            else:
                priority /= 3.5
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 4.5
            else:
                priority -= np.exp(-ratio * 1.4) * 3.5
            for m in range(1, 9):
                priority += ((0.4 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.2) * ((-1)**m)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.15 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.0) * ((-1)**t)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.6) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 9):
                priority += ((0.15 - ratio) ** u) / (u * 9) * np.cos(item * u * 0.85) * ((-1)**u)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 2 * bin_cap) * 6.5
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.35
            else:
                priority -= np.cos(ratio * (i + idx) * 1.3) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.4) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.2) * 0.7
        if i % 5 == 0:
            for w in range(1, 4):
                priority += np.sin(ratio * (i + w) * 0.8) * (w * 0.1)
        priorities[i] = priority
    return priorities
